INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1986', 'Hacienda del Alamo - Murcie: superbes appartements 2 chambres', '', '', 'Découvrez ces appartements neufs situés dans le prestigieux Hacienda del Álamo Golf Resort, l?un des complexes résidentiels les plus réputés de la Costa Cálida. Ce lotissement fermé offre un environnement naturel exceptionnel, une grande tranquillité et une qualité de vie incomparable. Le lotissement est composé de petites phases de seulement 2 blocs de 6 logements chacun, ce qui garantit l''intimité et une ambiance chaleureuse. Chaque appartement comprend : - 2 chambres et 2 salles de bains complètes - De vastes terrasses pour profiter du climat ensoleillé - Des finitions soignées et des prestations haut de gamme - Une place de parking privée et et un débarras Vous pourrez choisir entre un rez-de-chaussée avec jardin privé, un étage intermédiaire avec grande terrasse ou un penthouse avec terrasse et solarium privatif. La résidence comprend une piscine communautaire entourée de jardins paysagers. Hacienda del Álamo Golf Resort est une adresse de prestige sur la Costa Cálida, avec un large éventail de services et d?équipements : - Terrain de golf 18 trous de niveau professionnel - Hôtel 4 étoiles avec spa et centre de bien-être - Restaurants, bars et supermarché sur place - Installations sportives, espaces verts et aires de loisirs - Sécurité 24h/24 et accès contrôlé L?ensemble résidentiel recrée le charme d?un village méditerranéen, avec des ruelles calmes et une architecture typique. Prix: à partir de 196.900 ?', '', '', 196900, 'hacienda-del-alamo-murcie-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1913', 'Algorfa: superbes appartements 2 chambres sur le golf entièrement meublés et équipés !', '', '', 'Superbes appartements situés sur le golf de La Finca, à proximité de Algorfa, et à 10 minutes des belles plages de Guardamar. Situation idéale, au calme, facilement accessible via l''aéroport international d''Alicante. La résidence, entourée par la nature et avec de magnifiques vues sur le golf, propose 40 appartements, situés autour d''une belle piscine commune et de beaux espaces verts. La résidence offre également une aire de jeux pour enfants, un terrain de pétanque, un mini-golf et une zone de fitness extérieure. L''urbanisation offre en outre toutes les commodités: magasins, plusieurs restaurants, un hôtel 5* avec spa. Le domaine de golf est connu pour sa tranquillité et son exclusivité, l''endroit idéal pour ceux qui aiment le luxe et la nature. Les appartements, vendus complètements meublés et équipés, disposent de 2 chambres et de 2 salles de bains, d''une cuisine équipée ouverte sur un salon lumineux et d''une belle terrasse de 28 m². Vous pourrez choisir entre un appartement au rez-de-chaussée avec terrasse, ou un appartement au 1er étage avec terrasse et vaste solarium. Prix: à partir de 268.000 ? hors frais Inclus dans le prix: meubles, électros, climatisation, place de parking et remise. Fin des travaux: décembre 2025 ou juillet 2026', '', '', 268000, 'algorfa-superbes-appartements-2-chambres-sur-le-golf-entierement-meubles-et-equipes', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1914', 'Dolores: beux appartements de style méditerranéen en 3 chambres', '', '', 'Cette belle petite résidence, au style méditerranéen, est située à Dolores. Son emplacement est idéal pour qui recherche la tranquillité et un accès facile à toutes les commodités. A courte distance de marche du centre de Dolores, vous trouverez des magasins, supermarchés, cafés et restaurants. L''aéroport d''Alicante se trouve à 30 minutes et les superbes plages de Guardamar à 15 minutes. Les appartements sont spacieux et proposent 3 chambres, 2 salles de bains et une cuisine ouverte donnant sur un salon lumineux avec baies vitrées vers la terrasse. Au rez-de-chaussée, les appartements disposent de minimum 48 m² de terrasses, réparties à l''avant et à l''arrière de l''appartement. Au 1er étage, les appartements bénéficient d''une terrasse de 14 m², ainsi que d''un vaste solarium de 64 m². Chaque appartement dispose d''une place de parking extérieure et d''une remise. La résidence compte une belle piscine commune. Prix: Rez-de-chaussée: à partir de 249.900 ? hors frais 1er étage: à partir de 269.900 ? hors frais Fin des travaux: sept 2026', '', '', 249900, 'dolores-beux-appartements-de-style-mediterraneen-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1983', 'Torrevieja: appartements modernes 2 chambres complètement équipés', '', '', 'Découvrez ce tout nouveau complexe résidentiel situé dans le quartier paisible de La Siesta, à Torrevieja, qui allie design contemporain, confort et qualité de vie. Les appartements, spacieux et lumineux, offrent 2 chambres et 2 salles de bains, ainsi que de grandes terrasses pour profiter du climat méditerranéen. La résidence comprend les équipements suivants : - Piscines pour adultes et enfants - Jardins paysagers - Espace barbecue - Aire de jeux pour enfants - Court de padel et terrain de pétanque - Communauté sécurisée avec accès contrôlé Implanté entre les lagunes salées naturelles de La Mata et de Torrevieja, le complexe bénéficie d?un cadre naturel exceptionnel tout en restant proche des commodités. À seulement 3,5 km des plages et à quelques minutes des supermarchés, restaurants, centres de santé et du parc naturel de La Mata, cet emplacement offre un équilibre parfait entre tranquillité et vie urbaine. - Plages de Torrevieja : 3,5 km - Golf La Marquesa (Ciudad Quesada) : 7 km - Centre commercial Habaneras : 2 km - Aéroport d?Alicante : 40 km Prix: à partir de 293.000 ? hors frais Inclus dans le prix: - Place de parking souterrain et débarras - meubles - électroménagers - luminaires - climatisation Livraison: mars, mai ou juin 2027 * Les photos intérieures sont les photos d''une phase précédente', '', '', 293000, 'torrevieja-appartements-modernes-2-chambres-completement-equipes', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1933', 'DERNIERE UNITE ! Los Alcazares: beaux appartements 2 chambres dans un golf prestigieux', '', '', 'Située à seulement 25 minutes de l?aéroport de Murcie et à 55 minutes de celui d?Alicante, Los Alcázares est une destination idéale sur la Costa Calida. Parfaitement reliée aux principales villes comme Cartagena, Murcia et Alicante, ainsi qu?aux plages magnifiques de la Costa Cálida et de la Costa Blanca, cette localité offre un accès facile à tout ce que la région a de mieux à offrir. Cette nouvelle résidence comprend 16 appartements modernes de 2 et 3 chambres, ainsi que 6 villas exclusives de 3 chambres, alliant design contemporain, qualité et fonctionnalité. Les résidents profiteront d?une vue imprenable sur le prestigieux parcours de golf de La Serena et la splendide Mar Menor. Le complexe est situé à 2km des plages de la Mar Menor et en première ligne du parcours de golf de La Serena, réputé pour ses lacs pittoresques et sa végétation luxuriante. Ce parcours, avec ses obstacles d''eau sur 16 des 18 trous, offre un défi stratégique passionnant pour les golfeurs de tous niveaux. De plus, les résidents bénéficient d?un accès direct à pied au centre-ville, alliant ainsi calme et commodités locales. Les appartements 2 chambres sont situés au rez-de-chaussée ou au 1er étage. Chaque appartement dispose d''une place de parking et d''une cave. La résidence compte également une belle piscine commune avec jacuzzi Prix: Rez-de-chaussée: 275.000 ? hors frais Fin des travaux : 4T2026', '', '', 280900, 'derniere-unite-los-alcazares-beaux-appartements-2-chambres-dans-un-golf-prestigieux', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1942', 'Roldan : belles maisons jumelées en 2 chambres', '', '', 'Découvrez ces magnifiques maisons jumelées, situées à Roldán, dans la commune de Torre Pacheco. Ces villas modernes, de plain-pied, proposent 2 chambres, 2 salles de bains, une cuisine ouverte sur le salon, des placards encastrés et un solarium privé avec cuisine d''été. Chaque villa dispose d?un jardin privé, d?une piscine et d?un espace de stationnement. Roldán est une ville traditionnelle qui vous offre toutes les commodités nécessaires au quotidien : supermarchés, restaurants, bars, clinique, pharmacie, poste de police, station-service, mécaniciens, dentistes, médecins, et bien plus encore. Les célèbres golfs de La Torre et Terrazas sont à proximité, l''aéroport de Corvera se trouve à seulement 15 minutes et les plages de Mar Menor sont accessibles en 20 minutes de voiture. Prix: à partir de 239.500 ? hors frais Inclus: frigo, four, lave-vaisselle, taque et hotte Remise des clés : décembre 2026', '', '', 239500, 'roldan-belles-maisons-jumelees-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1906', 'Mojacar: superbes appartements 2 chambres avec vue sur mer', '', '', 'Ce superbe resort exclusif et moderne est situé dans un emplacement unique en Costa Alméria: à quelques pas de la mer, à 10 km de Mojacar, à 12 km de Gorracha et à la lisière du parc naturel de Cabo de Gata. Vous pourrez profiter de toutes les installations du resort, telles que piscine à débordement, piscine intérieure, espace chill, jardins, club social, clubhouse avec restaurants, centre sportif, magasins,... Les amateurs de golf pourront s''entrainer sur le parcours 18 trous en bord de Méditerranée. Les 125 appartements, répartis sur 3 niveaux, jouissent de belles terrasses et d''une vue à couper le souffle sur la mer. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine équipée ouverte avec baies vitrées vers la terrasse, d''une place de parking et d''une remise. Prix: à partir de 361.000 ? hors frais Inclus: - électroménagers - climatisation', '', '', 361000, 'mojacar-superbes-appartements-2-chambres-avec-vue-sur-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1907', 'Alenda Golf: superbes appartements 3 chambres', '', '', 'Ces beaux appartements 3 chambres sont idéalement situées au calme sur le golf d''Alenda, à Monforte del Cid, à seulement 15 minutes des belles plages d''Alicante, de l''aéroport et de Elche. Les duplex disposent tous de 2 salles de bains, d''une cuisine ouverte (avec taque vitrocéramique, four, micro-ondes et hotte), et d''une place parking. Vous jouirez de belles vues soit sur le parcours de golf, soit sur la Sierra de las Aguilas. La résidence dispose d''une piscine commune entourée de beaux jardins. Le village historique de Monforte del Cid se trouve à proximité. Prix: Duplex 3 chambres: 269.000 ? hors frais Inclus: - place de parking en sous-sol ou en extérieur (avec pré-installation pour véhicule électrique) - climatisation - taque vitrocéramique, four, micro-ondes, hotte Fin des travaux: septembre 2027', '', '', 269000, 'alenda-golf-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1912', 'San Pedro del Pinatar: superbes appartements 3 chambres', '', '', 'En plein coeur de San Pedro del Pinatar, découvrez cette belle résidence de 57 appartements 2 ou 3 chambres. De nombreuses facilités se trouvent à distance de marche et les belles plages de la Mar Menor sont à seulement 3 km. Les spacieux appartements 3 chambres disposent de 2 salles de bains, d''une cuisine équipée ouverte donnant sur le vaste salon avec portes-fenêtres vers la terrasse. Tous les appartements disposent d''une place de parking et d''une cave en sous-sol. La résidence compte une belle grande piscine commune entourée de beaux jardins. Prix A partir de 293.900 ? hors frais Penthouse: à partir de 319.900 ? hors frais', '', '', 293900, 'san-pedro-del-pinatar-superbes-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1920', 'Fuente Alamo: belles maisons modernes en 2 chambres', '', '', 'Ces nouvelles maisons sont situées à La Pinilla de Fuente Alamo, dans la région de Murcie. Cet emplacement offre un cadre naturel exceptionnel, loin de l''agitation des grandes villes et de la pression touristique de la côte. Ce nouveau projet privilégie l''efficacité énergétique, l''utilisation de matériaux respectueux de l''environnement et l''intégration harmonieuse dans l''environnement rural. Fuente Alamo est situé à 22 km au nord-ouest de Carthagène et à 35 km au sud-ouest de Murcie. La ville se trouve dans le bassin de la Mar Menor, entourée des montagnes d''Algarrobo, Los Gómez, Los Victorias et du Carrascoy. Fuente Álamo se trouve à 30 minutes de l''aéroport de Murcie-Corvera et à 26 km des belles plages de Bolnuevo. - Maisons 2 chambres et 2 salles de bains - Cuisine ouverte et living lumineux - Solarium de 44 m² - Piscine privée en option Prix: à partir de 193.750 ? hors frais (avec piscine) Fin des travaux: 2T2027', '', '', 189035, 'fuente-alamo-belles-maisons-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1916', 'Aguilas: beaux 3 chambres appartements à 300 m de la plage', '', '', 'Découvrez cette nouvelle résidence, idéalement située à Aguilas, à 300 m des plages. Aguilas est une charmante ville côtière à l''atmosphère animée et dispose de toutes les facilités telles que nombreux commerces, bars, restaurants,... Le projet comprend au total 105 appartements 2 et 3 chambres. Chaque appartement dispose d''une place de parking et d''une remise. La résidence compte une belle piscine commune, une salle de gym ainsi qu''un salon social. Prix: à partir de 234.000 ? hors frais Inclus: Taque à induction, hotte, four et micro-ondes. Fin des travaux: fin 2027', '', '', 234000, 'aguilas-beaux-3-chambres-appartements-a-300-m-de-la-plage', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1919', 'Cuevas de Almanzara : beaux appartements typiques en 2 chambres, clés en main', '', '', 'Ces superbes appartements de style espagnol sont situés dans un très beau terrain de golf, en Costa de Alméria, à Cuevas de Almanzara. Le terrain de golf est magnifique et offre une sélection de services et d''installations de loisirs tels que : terrain de cricket professionnel, 2 restaurants, boutique de golf, gymnase, terrain de football, académie de tennis, spa, etc. Les appartements sont situés dans une charmante cour de style espagnol, entourée de jardins magnifiquement aménagés et offrant un accès à une piscine commune. L''appartement comprend 2 chambres et 2 salles de bains. Le salon et la salle à manger spacieux s''ouvrent sur une terrasse ensoleillée. La cuisine ouverte est entièrement équipée (réfrigérateur/congélateur, lave-linge, taque vitrocéramique, four à micro-ondes et hotte). L''appartement comprend également l''air conditionné et une place de parking. Située au sein d''une communauté fermée et sécurisée, avec un service de sécurité 24h/24 et 7j/7, cette résidence offre la tranquillité d''esprit dans un environnement prestigieux et exclusif. Prix: de 195.000 ? à 225.000 ? hors frais 3 chambres : 235.000 ? hors frais', '', '', 195000, 'cuevas-de-almanzara-beaux-appartements-typiques-en-2-chambres-cles-en-main', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1921', 'Torre Pacheco: penthouses modernes en 2 chambres', '', '', 'Nouveaux appartements modernes à vendre à Torre Pacheco, au c?ur de la Costa Cálida. Chaque appartement dispose d''un salon spacieux avec cuisine ouverte, de deux ou trois chambres spacieuses avec placards, de deux salles de bains, dont l''une est attenante à la chambre principale, d''une belle terrasse et d''une place de parking en sous-sol. Les penthouses disposent d''un solarium privé sur le toit où vous pourrez vous détendre et admirer la vue imprenable. Si vous choisissez l''un des penthouses, vous disposerez également d''un barbecue, d''un évier et de jardinières sur votre terrasse. Belle piscine avec jardins communs. La résidence se trouve à distance de marche du centre de Torre Pacheco, une municipalité tranquille et agréable, avec toutes les commodités dont vous avez besoin : supermarchés, bars, pharmacies, écoles, restaurants, etc. De plus, elle est très bien reliée par la route à l''aéroport international de Murcie et aux plages de la Mar Menor, où vous pourrez profiter du climat méditerranéen et des eaux chaudes et cristallines. Les golfeurs seront intéressés de savoir qu''il y a un club de golf à proximité avec d''excellents services et plusieurs terrains de golf dans un rayon de 10 à 25 minutes en voiture. L''autoroute AP-7 et la route nationale N-332 relient également la municipalité à d''autres lieux intéressants à visiter, tels que Pilar de la Horadada, San Pedro del Pinatar, Orihuela Costa, Torrevieja ou Alicante, ainsi qu''à l''aéroport international de Murcie, accessible en seulement 20 minutes. Prix : Penthouses à partir de 192.000 ? hors frais', '', '', 192000, 'torre-pacheco-penthouses-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1922', 'Torre Pacheco: appartements modernes en 3 chambres', '', '', 'Nouveaux appartements modernes à vendre à Torre Pacheco, au c?ur de la Costa Cálida. Chaque appartement dispose d''un salon spacieux avec cuisine ouverte, de deux ou trois chambres spacieuses avec placards, de deux salles de bains, dont l''une est attenante à la chambre principale, d''une belle terrasse et d''une place de parking en sous-sol. Les penthouses disposent d''un solarium privé sur le toit où vous pourrez vous détendre et admirer la vue imprenable. Si vous choisissez l''un des penthouses, vous disposerez également d''un barbecue, d''un évier et de jardinières sur votre terrasse. Belle piscine avec jardins communs. La résidence se trouve à distance de marche du centre de Torre Pacheco, une municipalité tranquille et agréable, avec toutes les commodités dont vous avez besoin : supermarchés, bars, pharmacies, écoles, restaurants, etc. De plus, elle est très bien reliée par la route à l''aéroport international de Murcie et aux plages de la Mar Menor, où vous pourrez profiter du climat méditerranéen et des eaux chaudes et cristallines. Les golfeurs seront intéressés de savoir qu''il y a un club de golf à proximité avec d''excellents services et plusieurs terrains de golf dans un rayon de 10 à 25 minutes en voiture. L''autoroute AP-7 et la route nationale N-332 relient également la municipalité à d''autres lieux intéressants à visiter, tels que Pilar de la Horadada, San Pedro del Pinatar, Orihuela Costa, Torrevieja ou Alicante, ainsi qu''à l''aéroport international de Murcie, accessible en seulement 20 minutes. Prix : à partir de 196.000 ? hors frais Penthouses à partir de 233.000 ? hors frais', '', '', 196000, 'torre-pacheco-appartements-modernes-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1925', 'Relleu : beaux appartements 3 chambres', '', '', 'Cette nouvelle résidence est située à Relleu, un beau petit village de montagne tranquille, à 15 km de l''autoroute, à 18 km de la plage de Villajoyosa et à 25 km de la plage de Benidorm. Le village de Relleu est l''endroit idéal pour les amateurs de montagne, de cyclisme, de randonnées, de canyoning ou d''autres sports. La résidence compte 7 étages. Au sous-sol, il y a 69 places de parking et 42 caves. Au rez-de-chaussée se trouve la piscine intérieure chauffée, une grande salle à l''usage de tous les propriétaires et deux locaux commerciaux. La piscine extérieure avec ses terrasses se trouve sur le toit. Les appartements, orientés sud-est, disposent de 3 chambres, de 2 salles de bains et d''un WC séparé. Les terrasses offrent des vues spectaculaires et totalement dégagées. Les belles montagnes, le lac et les zones sportives sont magnifiques. Un parking souterrain et un débarras sont disponibles en option moyennant un supplément. Pour la détente, vous bénéficiez d''une piscine intérieure et d''une piscine extérieure, d''un sauna, d''une salle de fitness. À côté de la résidence se trouvent un supermarché, de bons restaurants et bars, un centre médical. Le centre sportif du village, auquel tous les habitants ont accès, avec terrain de football en gazon artificiel, terrain de padel, terrain de handball et gymnase se trouve également à proximité. Prix: de 229.000 ? à 235.000 ? hors frais Inclus: taque à induction, hotte et four, climatisation Fin des travaux: septembre 2025', '', '', 229000, 'relleu-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1946', 'Pilar de la Horadada : superbes appartements 3 chambres', '', '', 'Découvrez ce tout nouveau complexe résidentiel situé à Pilar de la Horadada, un lieu privilégié sur la Costa Blanca, à seulement 2 km des plages. La résidence offre des espaces communs de qualité, comprenant une piscine, des jardins paysagers et une aire de jeux pour enfants, faisant de cet endroit un lieu parfait pour toute la famille. La résidence compte des maisons 3 chambres, des appartements 3 chambres sur 3 niveaux, ou des appartements 3 chambres sur 2 niveaux. Pour les appartements 3 chambres et 2 salles de bains sur 3 niveaux, 3 options sont possibles : - Appartements au rez-de-chaussée avec jardins privés. - Appartements à l''étage intermédiaire avec de grandes terrasses. - Penthouses avec solarium privé. Chaque propriété est pensée dans un style moderne et fonctionnel, offrant des matériaux de qualité et des finitions contemporaines: Pilar de la Horadada est une ville côtière située au sud de la Costa Blanca, bénéficiant d''un climat agréable et d?une qualité de vie remarquable. Sa rue principale, vivante et dynamique, regorge de commerces, supermarchés, restaurants et autres services essentiels. À seulement 5 minutes en voiture, vous découvrirez les magnifiques plages de Torre de la Horadada et de Mil Palmeras, idéales pour profiter du soleil, du sable doré et de la mer. La région offre également de nombreuses pistes cyclables, des sentiers de randonnée et des possibilités d''activités sportives. Distances clés : - Terrain de golf Lo Romero ? 5 km (10 minutes en voiture) - Aéroport de Corvera (Murcie) ? 40 km (40 minutes en voiture) - Aéroport d''Alicante ? 55 km (55 minutes en voiture) - Centre commercial Zenia Boulevard ? 15 km (15 minutes en voiture) - Marina Torre de la Horadada ? 3 km (5 minutes en voiture) Prix : A partir de 299.900 ? hors frais Inclus: électroménagers Fin des travaux : octobre 2026 * Les images intérieures sont celles de phases précédentes.', '', '', 299900, 'pilar-de-la-horadada-superbes-appartements-3-chambres-3', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1929', 'Algorfa: beaux appartements 3 chambres', '', '', 'Nouvelle construction résidentielle de 41 appartements et penthouses élégants à Algorfa. Niché au c?ur d''un village traditionnel, Algorfa offre un mélange parfait de charme espagnol et d''équipements modernes, ce qui en fait une destination idéale pour les touristes et les habitants. La résidence est située à distance de marche du centre-ville, des écoles et du terrain de golf de La Finca. À seulement 15 minutes des belles plages et des hôpitaux. L''aéroport se trouve à 35 minutes en voiture. Les appartements 3 chambres disposent de 2 salles de bains, d''une cuisine ouverte donnant sur le living et d''une buanderie. Les penthouses modernes disposent d''un solarium privé. Label énergétique A. Place de parking et remise. Accès à une piscine commune pour la détente et les loisirs. Une salle de sport sur place pour les amateurs de santé et de fitness. Prix: à partir de 185.709 ? hors frais Fin des travaux : mars 2026', '', '', 185709, 'algorfa-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1930', 'Pinoso : belles villas 3 chambres', '', '', 'Villas indépendantes et modernes qui peuvent être construites sur des terrains rustiques ou urbains, nous avons une large gamme disponible dans la région de Pinoso : - 3 chambres, 2 salles de bains, toilettes pour invités - Piscine privée - Installation complète de l''air conditionné - Cuisine entièrement équipée - Grand choix de matériaux de qualité - Électricité et eau courante - 4 panneaux solaires inclus - Label énergétique AA - Choix de parcelles à partir de 10 000 m2 dans différents endroits. - Terrain clôturé de 3.000 m² pour un entretien facile - Portail coulissant motorisé Sur les parcelles, environ 3.000 m2 du terrain total seront clôturés et les villas seront livrées avec environ 1.000 m2 de gravier autour de la maison. Il y a plusieurs terrains rustiques à choisir dans différents endroits, chacun avec un prix différent (dans les prix publiés dans cette annonce, un terrain d''une valeur de 40.000 ? a été considéré, si l''acheteur choisit un autre terrain, le prix final sera recalculé en conséquence). Le délai de livraison est de 8 mois à compter de l''octroi du permis de construire. Si vous recherchez un environnement calme, proche de villages espagnols typiques, entouré de montagnes, c''est l''endroit idéal ! La belle ville prospère de Pinoso se trouve à environ 45 minutes d''Alicante et des plages de sable blanc de la Costa Blanca. Elle compte un peu moins de 8 000 habitants. Pinoso, également connue sous le nom de El Pinos, doit son nom aux pins qui couvrent les chaînes de montagnes de la région. Pinoso offre un style de vie rural espagnol, sans feux de circulation, pratiquement sans trafic, les seuls embouteillages étant causés par les tracteurs qui transportent les raisins à la Bodega. Les champs sont plantés de vignes, d''amandes et d''olives. En février, les champs se couvrent de fleurs d''amandiers roses. Pinoso compte de nombreux bars, restaurants et magasins, un nouveau centre médical ouvert 24 heures sur 24, des dentistes, deux écoles primaires et une école secondaire, un théâtre. Il y a un excellent centre sportif avec des piscines extérieures, des courts de tennis, des terrains de football et un gymnase, une bibliothèque et de nombreuses autres installations, dont une belle aire de pique-nique parmi les pins, avec des barbecues, des sièges et de l''eau courante. Prix: à partir de 317.000 ? hors frais', '', '', 317000, 'pinoso-belles-villas-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1931', 'Ciudad Quesada: superbes appartements 2 chambres entièrement équipés', '', '', 'Niché dans un emplacement de choix, à Lo Marabú, Ciudad Quesada, ce lotissement offre un accès facile aux services essentiels tout en proposant un environnement serein et tranquille. À quelques minutes en voiture, vous trouverez les magnifiques lagunes salées de La Mata et de Torrevieja, un paradis pour les amoureux de la nature, les photographes et les personnes en quête de bien-être. À seulement 15 minutes en voiture, les plages préservées de Guardamar del Segura vous invitent à profiter des dunes dorées et des eaux cristallines. Les amateurs de plein air trouveront dans la région de nombreux sentiers de randonnée et pistes cyclables, tandis que les golfeurs apprécieront la proximité de plusieurs terrains de golf prestigieux. Excellente connectivité et points forts locaux. Stratégiquement situé à Rojales, Alicante, ce projet offre d''excellentes infrastructures et connexions : Aéroport Alicante-Elche (ALC) : 38 km (35 minutes en voiture). Aéroport de Murcia-Corvera (RMU) : 65 km (50 minutes en voiture). Les centres commerciaux, les restaurants et les services quotidiens sont accessibles à pied. La résidence compte 84 appartements 2 chambres et 2 salles de bains. Les cuisines ouvertes sont entièrement équipées et donnent sur un beau living avec baies vitrées vers la terrasse. Les appartements du rez-de-chaussée disposent d?un jardin privé, ceux du 1er étage jouissent d?un beau solarium. Place de parking et débarras. La résidence compte une belle zone commune avec piscine et jardins paysagers. Prix : à partir de 279.000 ? hors frais Inclus : - Place de parking - Débarras - Chauffage par le sol dans les salles de bains - Électroménagers - Climatisation - Pack de meubles Fin des travaux : entre mai et août 2026 * les photos intérieures sont celles d''une phase précédente', '', '', 279000, 'ciudad-quesada-superbes-appartements-2-chambres-entierement-equipes', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1935', 'Torre Pacheco: villas modernes en 2 chambres', '', '', 'Découvrez le parfait mélange de design contemporain, de confort et d?emplacement avec ces magnifiques villas à Torre-Pacheco, dans la région de Murcie. Que vous soyez à la recherche d''une résidence principale, d''une maison de vacances ou d''un investissement immobilier, ces villas individuelles allient élégance, fonctionnalité et un excellent rapport qualité-prix dans l?une des zones les plus prisées d?Espagne. Ces villas de plain-pied, modernes et lumineuses, disposent de 2 chambres et 2 salles de bains, et sont pensées pour offrir un cadre de vie agréable et spacieux. Chaque villa comprend : - Une piscine privée : équipée d?une douche extérieure, d?un système de filtration et d?un éclairage LED. - Un solarium avec cuisine d?été : comprenant un évier, une pré-installation pour machine à laver et un mini-réfrigérateur, accessible par un escalier extérieur. - Des appareils électroménagers de qualité : plaque vitrocéramique, four, micro-ondes à colonne, réfrigérateur, hotte aspirante et lave-vaisselle intégré de marque Balay. - Des finitions soignées : sanitaires en porcelaine de première qualité dans les salles de bains, armoires entièrement équipées avec portes laquées blanches, et éclairage LED intérieur et extérieur à faible consommation d?énergie. Ces villas sont situées dans le pittoresque village de Torre Pacheco, un lieu dynamique offrant toutes les commodités essentielles, telles que des supermarchés, des banques, des bars et des restaurants. Torre-Pacheco et ses environs bénéficient d?une qualité de vie exceptionnelle grâce à leur climat méditerranéen et leurs nombreuses activités de plein air. Prix: à partir de 264.900 ? hors frais Fin des travaux : décembre 2026', '', '', 264900, 'torre-pacheco-villas-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1932', 'Aguilas : appartements 2 chambres à 800m de la mer', '', '', 'Découvrez ce nouveau complexe résidentiel à Águilas, composé de 36 appartements modernes de 2 et 3 chambres, répartis sur 4 blocs. Le complexe offre des équipements de qualité, dont 2 piscines communes, un garage avec des places de parking privatives et une salle de stockage pour chaque propriété. Pensé pour offrir une expérience de vie exceptionnelle, cette résidence dispose de vastes terrasses au rez-de-chaussée et au premier étage, ainsi que de solariums spacieux au dernier étage, offrant des vues imprenables sur l?horizon. Chaque logement bénéficie de cuisines et de salles de bains entièrement équipées et d?une pré-installation pour la climatisation. Le complexe est idéalement situé à seulement 800 mètres de la mer et à proximité d?un centre commercial, vous assurant un quotidien pratique et agréable. Águilas est une destination idéale sur la Costa Cálida, à seulement 50 minutes du nouvel aéroport de Murcie ou d''Almeria, et à 1h30 de l?aéroport d?Alicante. La ville, charmante et accueillante, propose de nombreuses commodités et se distingue par son long littoral propice à la baignade, à la détente et aux activités en plein air telles que la plongée, les sports nautiques, la randonnée ou le golf. Avec ses 28 kilomètres de côtes, Águilas vous invite à explorer ses 35 plages, allant des criques sauvages aux plages urbaines. Son climat doux, chaud et désertique, avec une température moyenne annuelle de 22°C, vous garantit une qualité de vie exceptionnelle tout au long de l?année Prix: - de 212.000 ? à 272.000 ? hors frais - penthouses avec solarium : 297.000 ? hors frais Inclus: Électroménagers: frigo, four, hotte, plaque à induction, micro-ondes et lave-vaisselle. Fin des travaux : juin 2026', '', '', 212000, 'aguilas-appartements-2-chambres-a-800m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1937', 'Bigastro: belles maisons typiques en 4 chambres', '', '', 'Nouveau projet de 10 magnifiques maisons jumelées à Bigastro. Bigastro est une petite ville de la Vega Baja, au sud d''Alicante. Elle se distingue par ses excellentes connexions grâce à l''AP-7, qui la place à seulement 15 minutes des plages de Guardamar et à 30 minutes de l''aéroport d''Alicante. De plus, Orihuela est à seulement 5 minutes. Bigastro dispose de tous les services nécessaires, ce qui explique que de nombreuses personnes choisissent cette destination comme lieu de résidence. Chaque maison disposera de : - 4 chambres et 3 salles de bains - Solarium privé de 39 m2 avec des vues incroyables. - Parking individuel fermé en sous-sol avec accès direct à la propriété. - terrain privé avec possibilité de placer une piscine (en option) Piscine commune pour la résidence. Prix: à partir de 249.900 ? hors frais Inclus : électroménagers Livraison : mars 2026', '', '', 249900, 'bigastro-belles-maisons-typiques-en-4-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1938', 'Lomas de Cabo Roig : appartements 2 chambres restaurés à prix attractifs', '', '', 'Appartements entièrement restaurés à Lomas de Cabo Roig, l''un des quartiers les plus prisés d''Orihuela Costa. Ce complexe, construit en 2008, bénéficie d''une rénovation soignée de certaines de ses unités. Les appartements de 2 chambres et 2 salles de bains disposent d''une cuisine séparée entièrement équipée (sauf la machine à laver) et d''un grand salon donnant sur une terrasse de minimum 17 m². Les appartements du rez-de-chaussée ont un jardin, ceux du 3ème étage ont un solarium. La résidence propose une piscine commune et une aire de jeux pour les enfants. Des places de parking souterrain sont disponibles en option (moyennant supplément). Lomas de Cabo Roig est un quartier résidentiel de renom, situé à seulement 2 km des plages de Cabo Roig, célèbres pour leur beauté. Bien desservi, il offre une large gamme de services, tels que commerces, restaurants, supermarchés et centres commerciaux. Prix: 2 chambres à partir de 186.500 ? hors frais Appartements 1 chambre disponibles à partir de 132.500 ? hors frais Livraison: key ready ou mai 2026', '', '', 186500, 'lomas-de-cabo-roig-appartements-2-chambres-restaures-a-prix-attractifs', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2002', 'REVENTE ! Mil Palmeras: bel appartement 3 chambres avec solarium à 300 m de la mer', '', '', 'Opportunité à saisir! Appartement moderne et lumineux, clés en mains, idéalement situé à Mil Palmeras, à 300m de la mer, au 1er étage d''une petite copropriété calme. Il dispose de 3 chambres, de 2 salles de bains, d'' une cuisine équipée ouverte sur un beau séjour, et d''une terrasse orientée plein sud. Grand solarium privé avec vue sur mer. Piscine commune Emplacement recherché ! Prix: 349.500 ? hors frais, tout équipé (meubles, électroménagers, climatisation) Appartement détenu par le même propriétaire (client Secundo) depuis l?achat, historique connu.', '', '', 349500, 'revente-mil-palmeras-bel-appartement-3-chambres-avec-solarium-a-300-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1939', 'San Miguel de Salinas : superbes appartements modernes en 2 chambres', '', '', 'Découvrez ces magnifiques appartements modernes situés dans une résidence calme et verdoyante, à seulement 500 mètres du c?ur de San Miguel de Salinas. San Miguel de Salinas est un charmant village typique de la Costa Blanca, idéal pour vivre toute l''année grâce à son climat agréable et son atmosphère dynamique. Les plages d''Orihuela Costa se trouvent à 7 km et de nombreux parcours de golf sont situés dans les environs proches. Avec 2 chambres et 2 salles de bains, ces appartements allient confort et fonctionnalité, offrant des espaces de vie lumineux grâce à un design soigné. Les appartements disposent d?un grand salon donnant sur une belle terrasse de 21 m², idéale pour profiter des journées ensoleillées, d''une cuisine entièrement équipée d''électroménagers, d''un système de climatisation centralisée, d''une place de parking privée ainsi que d''une cave en sous-sol. Le complexe résidentiel se distingue par sa grande zone de jardin paysager et ses 3 piscines communes, parfaites pour se détendre tout en étant entouré de verdure. L''architecture du projet assure de grandes distances entre chaque bloc, garantissant une intimité et un cadre de vie agréable. Prix : A partir de 241.000 ? hors frais Dernier étage avec solarium : à partir de 316.000 ? hors frais', '', '', 241000, 'san-miguel-de-salinas-superbes-appartements-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
